9.1.2 System Monitoring Callbacks (JavaScript Example)
Demonstrates a hypothetical client-side handler for processing webhook notifications from WDIP's monitoring system.

// Example Node.js Express route handler for receiving WDIP monitoring webhooks

const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto'); // For signature verification

const app = express();

// Secret key shared with WDIP for webhook signature verification
const WEBHOOK_SECRET = process.env.WDIP_WEBHOOK_SECRET;

// Middleware to verify webhook signature (important for security)
function verifyWebhookSignature(req, res, buf, encoding) {
  if (!WEBHOOK_SECRET) {
    console.warn("Webhook secret not configured, skipping signature verification.");
    return; // Allow request if secret is not set (e.g., for testing)
  }
  const signature = req.headers['x-wdip-signature-sha256']; // More specific header name
  if (!signature || !signature.startsWith('sha256=')) {
      throw new Error('Webhook signature missing or invalid format');
  }
  const hmac = crypto.createHmac('sha256', WEBHOOK_SECRET);
  const digest = Buffer.from('sha256=' + hmac.update(buf).digest('hex'), 'utf8');
  const checksum = Buffer.from(signature, 'utf8');
  if (checksum.length !== digest.length || !crypto.timingSafeEqual(digest, checksum)) {
    throw new Error('Webhook signature invalid');
  }
  console.log("Webhook signature verified successfully.");
}

// Apply signature verification middleware only for the webhook endpoint
// Ensure body is parsed *after* raw body is available for verification
app.post('/webhook/monitoring', bodyParser.raw({ type: 'application/json', verify: verifyWebhookSignature }), (req, res, next) => {
  // Now parse the JSON body after verification
  try {
    req.body = JSON.parse(req.body.toString());
    next();
  } catch (e) {
    res.status(400).json({ status: "error", message: "Invalid JSON payload" });
  }
}, (req, res) => { // The actual handler
  const eventData = req.body;

  // Basic validation of the event structure
  if (!eventData || !eventData.event_id || !eventData.event_type || !eventData.payload) {
    console.error("Received invalid event data structure:", eventData);
    return res.status(400).json({ status: "error", message: "Invalid event structure" });
  }

  console.log(`Received monitoring event: ${eventData.event_id} (${eventData.event_type})`);

  // Process the event data (example logic)
  try {
    processMonitoringCallback(eventData);
    // Send acknowledgment back to WDIP
    res.status(200).json({ status: "received", event_id: eventData.event_id });
  } catch (error) {
    console.error(`Error processing event ${eventData.event_id}:`, error);
    // Indicate failure to WDIP (it might retry based on its policy)
    res.status(500).json({ status: "error", message: `Failed to process event: ${error.message}` });
  }
});

// Example function to process the received monitoring data
function processMonitoringCallback(eventData) {
  // Extract relevant data safely, providing defaults or checks
  const payload = eventData.payload || {};
  const { system = 'UnknownSystem', component = 'UnknownComponent', status = 'UnknownStatus', timestamp = new Date().toISOString(), severity = 'info', details = {} } = payload;

  console.log(`Processing callback: System=${system}, Component=${component}, Status=${status}, Severity=${severity}, Timestamp=${timestamp}`);

  // Example: Trigger an internal alert based on severity or status
  if (severity === "critical" || status === "failed" || status === "degraded") {
    triggerInternalAlert({
      message: `Issue detected in ${system}/${component}: ${status} (Severity: ${severity})`,
      timestamp: timestamp,
      details: details,
      wdip_event_id: eventData.event_id
    });
  }

  // Log the event to a local monitoring system/database
  logToLocalMonitoring({
      eventId: eventData.event_id,
      eventType: eventData.event_type,
      source: eventData.source,
      severity: severity,
      timestamp: timestamp,
      payload: payload,
      receivedAt: new Date().toISOString()
  });
}

