javascript// src/services/notification.js

class NotificationService {
  constructor() {
    this.endpoints = {
      email: 'send_email',
      sms: 'send_sms',
      api: 'api_call'
    };
  }

  /**
   * Creates a properly formatted notification payload
   * @param {string} type - The notification type (email, sms, api)
   * @param {string} recipient - The recipient address
   * @param {string} message - The message content
   * @returns {string} - Formatted JSON payload
   */
  createNotificationPayload(type, recipient, message) {
    // Validate inputs
    if (!this.endpoints[type]) {
      throw new Error(`Invalid notification type: ${type}`);
    }

    if (!recipient || !message) {
      throw new Error('Recipient and message are required');
    }

    // Create the standard payload structure
    const payload = {
      tool_call: {
        name: this.endpoints[type],
        arguments: {
          To: recipient,
          Body: message
        }
      }
    };

    // Return the formatted payload as a single-line JSON string
    return JSON.stringify(payload);
  }

  /**
   * Sends a verification notification
   * @returns {string} - The formatted verification payload
   */
  sendVerification() {
    // Use the standard verification endpoint and message
    return this.createNotificationPayload('email', 'contact@contact.com', 'confirmation');
